#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>
#include <stdint.h>

typedef struct Node {
    char *key;
    long long cnt;
    struct Node *next;
} Node;

#define TABLE_SIZE 2000003 /* a prime > 2*10^6 */

static Node *table[TABLE_SIZE];

static unsigned long long hash_str(const char *s){
    unsigned long long h = 0;
    while(*s){ h = h*131 + (unsigned char)(*s); s++; }
    return h;
}

static Node* find_node(const char *s, bool create){
    unsigned long long h = hash_str(s);
    size_t idx = h % TABLE_SIZE;
    Node *cur = table[idx];
    while(cur){
        if(strcmp(cur->key, s) == 0) return cur;
        cur = cur->next;
    }
    if(!create) return NULL;
    Node *node = (Node*)malloc(sizeof(Node));
    node->key = strdup(s);
    node->cnt = 0;
    node->next = table[idx];
    table[idx] = node;
    return node;
}

static bool is_pal(const char *s, int l, int r){ /* inclusive */
    while(l < r){ if(s[l] != s[r]) return false; l++; r--; }
    return true;
}

static void clear_table(){
    for(size_t i = 0; i < TABLE_SIZE; i++) {
        Node *cur = table[i];
        while(cur){
            Node *tmp = cur;
            cur = cur->next;
            free(tmp->key);
            free(tmp);
        }
        table[i] = NULL;
    }
}

int main(){
    int T; if(scanf("%d", &T) != 1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        getchar(); // consume newline after N
        char **arr = (char**)malloc(N * sizeof(char*));
        for(int i = 0; i < N; i++) {
            char buf[105];
            if(!fgets(buf, sizeof(buf), stdin)) buf[0] = '\0';
            size_t len = strlen(buf);
            if(len && buf[len-1] == '
') buf[--len] = '\0';
            arr[i] = strdup(buf);
            Node *node = find_node(arr[i], true);
            node->cnt++;
        }
        long long answer = 0;
        for(size_t idx = 0; idx < TABLE_SIZE; ++idx){
            for(Node *node = table[idx]; node; node = node->next){
                const char *s = node->key;
                int L = (int)strlen(s);
                bool pref[101];
                bool suff[101];
                for(int i = 0; i < L; i++) pref[i] = is_pal(s, 0, i);
                for(int i = 0; i < L; i++) suff[i] = is_pal(s, i, L-1);
                for(int pos = 0; pos <= L; ++pos){
                    /* t before s */
                    if(pos == 0 || pref[pos-1]){
                        int sufLen = L - pos;
                        char rev[101];
                        for(int k = 0; k < sufLen; k++) rev[k] = s[L-1 - k];
                        rev[sufLen] = '\0';
                        Node *partner = find_node(rev, false);
                        if(partner){
                            long long add = partner->cnt;
                            if(strcmp(s, rev) == 0) add -= node->cnt;
                            answer += add * node->cnt;
                        }
                    }
                    /* t after s */
                    if(pos == L || suff[pos]){
                        int preLen = pos;
                        char rev[101];
                        for(int k = 0; k < preLen; k++) rev[k] = s[preLen-1 - k];
                        rev[preLen] = '\0';
                        Node *partner = find_node(rev, false);
                        if(partner){
                            long long add = partner->cnt;
                            if(strcmp(s, rev) == 0) add -= node->cnt;
                            answer += add * node->cnt;
                        }
                    }
                }
            }
        }
        printf("%lld
", answer);
        for(int i = 0; i < N; i++) free(arr[i]);
        free(arr);
        clear_table();
    }
    return 0;
}
